    "path": "Platforms/iOS/Info.plist",
    "content": "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<!DOCTYPE plist PUBLIC \"-//Apple//DTD PLIST 1.0//EN\" \"http://www.apple.com/DTDs/PropertyList-1.0.dtd\">\n<plist version=\"1.0\">\n<dict>\n\t<key>ITSAppUsesNonExemptEncryption</key>\n\t<false/>\n\t<key>UIDeviceFamily</key>\n\t<array>\n\t\t<integer>1</integer>\n\t\t<integer>2</integer>\n\t</array>\n\t<key>UIRequiredDeviceCapabilities</key>\n\t<array>\n\t\t<string>arm64</string>\n\t\t<!--#if (bluetoothle || blehosting)-->\n\t\t<string>bluetooth-le</string>\n\t\t<!--#endif-->\n\t\t<!--#if (gps)-->\n\t\t<string>gps</string>\n\t\t<!--#endif-->\n\t\t<!--#if (health)-->\n\t\t<string>healthkit</string>\n\t\t<!--#endif-->\n\t</array>\n\t<key>UISupportedInterfaceOrientations</key>\n\t<array>\n\t\t<string>UIInterfaceOrientationPortrait</string>\n\t\t<string>UIInterfaceOrientationLandscapeLeft</string>\n\t\t<string>UIInterfaceOrientationLandscapeRight</string>\n\t</array>\n\t<key>UISupportedInterfaceOrientations~ipad</key>\n\t<array>\n\t\t<string>UIInterfaceOrientationPortrait</string>\n\t\t<string>UIInterfaceOrientationPortraitUpsideDown</string>\n\t\t<string>UIInterfaceOrientationLandscapeLeft</string>\n\t\t<string>UIInterfaceOrientationLandscapeRight</string>\n\t</array>\n\t<key>XSAppIconAssets</key>\n\t<string>Assets.xcassets/appicon.appiconset</string>\t\n\t<!--#if (gps || geofencing || usemaps)-->\n\t<key>NSLocationTemporaryUsageDescription</key>\n\t<string>Say something useful here that your users will understand</string>\n\t<key>NSLocationAlwaysUsageDescription</key>\n\t<string>Say something useful here that your users will understand</string>\n\t<key>NSLocationAlwaysAndWhenInUseUsageDescription</key>\n\t<string>Say something useful here that your users will understand</string>\n\t<key>NSLocationWhenInUseUsageDescription</key>\n\t<string>Say something useful here that your users will understand</string>\n\t<!--#endif-->\n\t<!--#if (gps)-->\n\t<key>NSLocationTemporaryUsageDescriptionDictionary</key>\n\t<dict>\n\t\t<key>shinygps</key>\n\t\t<string>This app wants to know EXACTLY where you are</string>\n\t</dict>\n\t<!--#endif-->\n\t<!--#if (bluetoothle || blehosting)-->\n\t<key>NSBluetoothPeripheralUsageDescription</key>\n\t<string>Say something useful here that your users will understand</string>\n\t<!--#endif-->\n\t<!--#if (bluetoothle)-->\n\t<key>NSBluetoothAlwaysUsageDescription</key>\n\t<string>Say something useful here that your users will understand</string>\t\n\t<!--#endif-->\n\t<!--#if (speechrecognition || shinyspeech || aiconversation)-->\n\t<key>NSSpeechRecognitionUsageDescription</key>\n\t<string>Say something useful here that your users will understand</string>\n\t<!--#endif-->\n\t<!--#if (audio || essentialsmedia || speechrecognition || cameraview || shinyspeech || aiconversation)-->\n\t<key>NSMicrophoneUsageDescription</key>\n\t<string>Say something useful here that your users will understand</string>\n\t<!--#endif-->\n\t<!--#if (essentialsmedia || screenrecord)-->\n\t<key>NSPhotoLibraryAddUsageDescription</key>\n\t<string>Say something useful here that your users will understand</string>\n\t<!--#endif-->\n\t<!--#if (essentialsmedia)-->\n\t<key>NSPhotoLibraryUsageDescription</key>\n\t<string>Say something useful here that your users will understand</string>\n\t<!--#endif-->\n\t<!--#if (essentialsmedia || barcodes || cameraview)-->\n\t<key>NSCameraUsageDescription</key>\n\t<string>Say something useful here that your users will understand</string>\n\t<!--#endif-->\n\t<!--#if (fingerprint)-->\n\t<key>NSFaceIDUsageDescription</key>\n\t<string>Say something useful here that your users will understand</string>\n\t<!--#endif-->\n\t<!--#if (calendar)-->\n\t<key>NSCalendarsUsageDescription</key>\n\t<string>We need to say something useful here</string>\n\t<key>NSCalendarsFullAccessUsageDescription</key>\n\t<string>We need to say something useful here</string>\n\t<!--#endif-->\n\t<!--#if (contactstore)-->\n\t<key>NSContactsUsageDescription</key>\n\t<string>Say something useful here that your users will understand</string>\n\t<!--#endif-->\n\t<!--#if (health)-->\n\t<key>NSHealthUpdateUsageDescription</key>\n\t<string>We need to say something useful here</string>\n\t<key>NSHealthShareUsageDescription</key>\n\t<string>We need to say something useful here</string>\n\t<!--#endif-->\n\t<!--#if (music)-->\n\t<key>NSAppleMusicUsageDescription</key>\n\t<string>This app needs access to your music library to browse and play your music</string>\n\t<!--#endif-->\n\t<!--#if (jobs || usepush || gps || geofencing || bluetoothle || blehosting || mediaelement)-->\n\t<key>UIBackgroundModes</key>\n\t<array>\n\t\t<!--#if (jobs || usepush)-->\n\t\t<string>processing</string>\n\t\t<string>fetch</string>\n\t\t<!--#endif-->\n\t\t<!--#if (gps || geofencing)-->\n\t\t<string>location</string>\n\t\t<!--#endif-->\n\t\t<!--#if (bluetoothle)-->\n\t\t<string>bluetooth-central</string>\n\t\t<!--#endif-->\n\t\t<!--#if (blehosting)-->\n\t\t<string>bluetooth-peripheral</string>\n\t\t<!--#endif-->\n\t\t<!--#if (usepush)-->\n\t\t<string>remote-notification</string>\n\t\t<!--#endif-->\n\t\t<!--#if (mediaelement)-->\n\t\t<string>audio</string>\n\t\t<!--#endif-->\n\t</array>\n\t<!--#endif-->\n\t<!--#if (jobs)-->\n\t<key>BGTaskSchedulerPermittedIdentifiers</key>\n\t<array>\n\t\t<string>com.shiny.job</string>\n\t\t<string>com.shiny.jobpower</string>\n\t\t<string>com.shiny.jobnet</string>\n\t\t<string>com.shiny.jobpowernet</string>\n\t</array>\n\t<!--#endif-->\n    <!--#if (usewebauthenticator)-->\n    <key>CFBundleURLTypes</key>\n    <array>\n        <dict>\n            <key>CFBundleURLName</key>\n            <string>My App</string>\n            <key>CFBundleURLSchemes</key>\n            <array>\n                <string>myapp</string>\n            </array>\n            <key>CFBundleTypeRole</key>\n            <string>Editor</string>\n        </dict>\n    </array>\n    <!--#endif-->\t\n\t<!--#if (usemsalbroker)-->\n\t<key>LSApplicationQueriesSchemes</key>\n    <array>\n        <string>msauthv2</string>\n        <string>msauthv3</string>\n    </array>\n    <key>CFBundleURLTypes</key>\n    <array>\n        <dict>\n            <key>CFBundleTypeRole</key>\n            <string>Editor</string>\n            <key>CFBundleURLName</key>\n            <string>{APPLICATION_ID}</string>\n            <key>CFBundleURLSchemes</key>\n            <array>\n                <string>msal{MSAL_CLIENT_ID}</string>\n                <string>msauth.{APPLICATION_ID}</string>\n            </array>\n        </dict>\n    </array>\n\t<!--#endif-->\n\t<!--#if (carplay)-->\n\t<key>UIApplicationSceneManifest</key>\n\t<dict>\n\t\t<key>UIApplicationSupportsMultipleScenes</key>\n\t\t<true/>\n\t\t<key>UISceneConfigurations</key>\n\t\t<dict>\n\t\t\t<key>UIWindowSceneSessionRoleApplication</key>\n\t\t\t<array>\n\t\t\t\t<dict>\n\t\t\t\t\t<key>UISceneClassName</key>\n\t\t\t\t\t<string>UIWindowScene</string>\n\t\t\t\t\t<key>UISceneConfigurationName</key>\n\t\t\t\t\t<string>__MAUI_DEFAULT_SCENE_CONFIGURATION__</string>\n\t\t\t\t\t<key>UISceneDelegateClassName</key>\n\t\t\t\t\t<string>SceneDelegate</string>\n\t\t\t\t</dict>\n\t\t\t</array>\n\t\t\t<key>CPTemplateApplicationSceneSessionRoleApplication</key>\n\t\t\t<array>\n\t\t\t\t<dict>\n\t\t\t\t\t<key>UISceneClassName</key>\n\t\t\t\t\t<string>CPTemplateApplicationScene</string>\n\t\t\t\t\t<key>UISceneConfigurationName</key>\n\t\t\t\t\t<string>CarPlay</string>\n\t\t\t\t\t<key>UISceneDelegateClassName</key>\n\t\t\t\t\t<string>CarPlaySceneDelegate</string>\n\t\t\t\t</dict>\n\t\t\t</array>\n\t\t</dict>\n\t</dict>\n\t<!--#endif-->\n</dict>\n</plist>\n"
